
INSERT INTO public.topic_sets (id, title, description, order_index, free_card_limit) VALUES
('11111111-1111-1111-1111-111111111111', 'Automation – Set A: Fundamentals, Laplace & Control Systems', 'Definitions, Nyquist, Laplace ODEs, partial fractions, pneumatic valves, DCS, microcontrollers, electrical vs thermal systems.', 1, 5),
('22222222-2222-2222-2222-222222222222', 'Automation – Set B: PID, Robotics, PLCs & Root Locus', 'PID/PD control, robot sensors, industrial robot types, PLC programs & architecture, poles & zeros, root locus, hydraulic valves.', 2, 5);

INSERT INTO public.cards (topic_set_id, order_index, question, answer) VALUES
-- SET A
('11111111-1111-1111-1111-111111111111', 1, 'Define a Supercomputer.', 'A computer with extremely high processing power and speed, used for complex scientific simulations, weather forecasting, and quantum mechanics calculations.'),
('11111111-1111-1111-1111-111111111111', 2, 'Define Hardware and Software.', 'Hardware: the physical, tangible components of a computer system (CPU, RAM, hard drive, motherboard). Software: a set of instructions, data, or programs used to operate computers and execute specific tasks (operating systems, compilers, applications).'),
('11111111-1111-1111-1111-111111111111', 3, 'What is a Modem?', 'A hardware device that modulates digital signals from a computer into analog signals for transmission over telephone lines, and demodulates incoming analog signals back to digital.'),
('11111111-1111-1111-1111-111111111111', 4, 'Define a Control System and give two examples.', 'A system that manages, commands, directs, or regulates the behavior of other devices or systems to achieve a desired output. Examples: cruise control, thermostat.'),
('11111111-1111-1111-1111-111111111111', 5, 'What is a Passive Transducer? Give two examples.', 'A transducer that requires an external power source to operate. Its output signal (resistance, capacitance) is a function of the measurand. Examples: thermistor, photoresistor.'),
('11111111-1111-1111-1111-111111111111', 6, 'State the Nyquist Stability Criterion.', 'A closed-loop system is stable iff the number of counter-clockwise encirclements of the critical point (-1, 0) by the Nyquist plot of G(s)H(s) equals the number of open-loop poles in the right-half s-plane. For a stable open-loop system, the plot must not encircle (-1, 0).'),
('11111111-1111-1111-1111-111111111111', 7, 'Give two specifications of a second-order underdamped system.', '1) Maximum Overshoot (Mp): the maximum amount the response overshoots the final steady-state value, as a percentage. 2) Settling Time (Ts): the time required for the response to reach and stay within a certain percentage (2% or 5%) of its final value.'),
('11111111-1111-1111-1111-111111111111', 8, 'Define SCADA.', 'Supervisory Control and Data Acquisition. A large-scale system for monitoring and controlling industrial processes across wide geographical areas (pipelines, power grids). It acquires data from remote sensors and sends control commands.'),
('11111111-1111-1111-1111-111111111111', 9, 'Define a Transducer.', 'A device that converts energy from one form to another. In measurement, it converts a physical quantity (pressure, temperature) into an electrical signal (voltage, current).'),
('11111111-1111-1111-1111-111111111111', 10, 'Define a Programmable Logic Controller (PLC).', 'An industrial digital computer designed for robust control of manufacturing processes (assembly lines, robotic devices). It uses a programmable memory to execute logic, sequencing, timing, and arithmetic operations.'),
('11111111-1111-1111-1111-111111111111', 11, 'Define Direct Digital Control (DDC).', 'A control system where a digital computer (microcontroller or microprocessor) directly adjusts the final control element (e.g., a valve) based on a pre-programmed control algorithm (e.g., PID). No intermediate analog controllers are used.'),
('11111111-1111-1111-1111-111111111111', 12, 'What is Cascade Control?', 'A control strategy where the output of one controller (master) serves as the setpoint for another controller (slave). Used to improve dynamic response and reject disturbances in systems with slow and fast dynamics.'),
('11111111-1111-1111-1111-111111111111', 13, 'What is Ratio Control?', 'A strategy used to maintain the ratio of two process variables (e.g., flows A and B) at a specified value (e.g., 2:1). One flow is the wild stream, and the other is controlled to maintain the ratio.'),
('11111111-1111-1111-1111-111111111111', 14, 'What is Pulse Width Modulation (PWM)?', 'A technique for controlling analog devices (motor speed, LED brightness) using a digital signal. It varies the duty cycle (ON-time vs period) of a square wave. 50% duty cycle = signal ON half the time.'),
('11111111-1111-1111-1111-111111111111', 15, 'What is a Sensor? How does it relate to a transducer?', 'A device that detects a physical property (heat, light, motion, pressure) and produces a corresponding output signal, typically electrical. All sensors are transducers, but not all transducers are sensors.'),
('11111111-1111-1111-1111-111111111111', 16, 'Define Protocols in industrial networks.', 'A set of established rules and standards governing how data is transmitted and exchanged between devices on a network. Examples: Modbus, Profibus, Ethernet/IP.'),
('11111111-1111-1111-1111-111111111111', 17, 'List the five major components of a robot.', '1) Manipulator (arm) – joints, links, end-effector. 2) End-effector (gripper/tool). 3) Actuators – electric, hydraulic, or pneumatic muscles. 4) Sensors – internal state and external environment feedback. 5) Controller (processor) – the brain that executes the program.'),
('11111111-1111-1111-1111-111111111111', 18, 'List five typical sensors used in robotics.', '1) Vision sensor (camera). 2) Ultrasonic sensor. 3) Force/torque sensor (strain gauges). 4) Inertial Measurement Unit (IMU). 5) Proximity sensor (inductive/capacitive).'),
('11111111-1111-1111-1111-111111111111', 19, 'Solve y'''' + 5y'' + 6y = 2e^(-t), y(0)=1, y''(0)=0 using Laplace.', 'Take Laplace: (s^2 Y - s) + (5sY - 5) + 6Y = 2/(s+1). Y(s)(s^2+5s+6) = 2/(s+1) + s + 5 = (s^2+6s+7)/(s+1). Factor: Y(s) = (s^2+6s+7)/[(s+1)(s+2)(s+3)] = 1/(s+1) + 1/(s+2) - 1/(s+3). Therefore y(t) = e^(-t) + e^(-2t) - e^(-3t).'),
('11111111-1111-1111-1111-111111111111', 20, 'Find inverse Laplace of F(s) = 1/[(s+1)^2 (s+2)].', 'PFD: A/(s+1) + B/(s+1)^2 + C/(s+2). Cover-up: B = 1, C = 1. Substitute s=0: 1 = 2A + 2 + 1 ⇒ A = -1. Therefore f(t) = -e^(-t) + t·e^(-t) + e^(-2t) = e^(-2t) - e^(-t) + t·e^(-t).'),
('11111111-1111-1111-1111-111111111111', 21, 'Explain the principle of operation of a pneumatic control valve.', 'A controller sends a 3–15 psi (0.2–1.0 bar) pneumatic signal to a spring-diaphragm actuator. The actuator converts pressure into linear force that moves a valve stem connected to a plug. The plug moves relative to a seat, changing the flow opening. Air-to-Close: rising pressure pushes plug onto seat. Air-to-Open: rising pressure lifts the plug. The spring provides fail-safe return when air is lost.'),
('11111111-1111-1111-1111-111111111111', 22, 'List the main components of a Distributed Control System (DCS).', '1) Field level: sensors and final control elements. 2) Local Control Unit (LCU) / distributed controllers running PID. 3) Communication network / redundant data highway (Ethernet, ControlNet). 4) Operator station (HMI). 5) Engineering workstation. 6) History server / data logger.'),
('11111111-1111-1111-1111-111111111111', 23, 'List the core elements of a microcontroller.', '1) CPU. 2) Memory: RAM (volatile) and ROM/Flash (program). 3) I/O ports (parallel & serial). 4) Timers/Counters (delays, PWM). 5) Analog-to-Digital Converter (ADC). 6) System bus (address, data, control).'),
('11111111-1111-1111-1111-111111111111', 24, 'Compare electrical and thermal systems (analogous quantities).', 'Effort: Voltage V ↔ Temperature difference ΔT. Flow: Current I ↔ Heat flow q. Resistance: R (V=IR) ↔ Rth (ΔT=q·Rth). Capacitance: C (I=C dV/dt) ↔ Cth (q=Cth dT/dt). Analogous equation: RC dV/dt + V = Vin ↔ Rth·Cth dT/dt + ΔT = qin·Rth.'),
('11111111-1111-1111-1111-111111111111', 25, 'State the Final Value Theorem and PWM duty cycle formula.', 'Final Value Theorem: lim(t→∞) f(t) = lim(s→0) sF(s). PWM duty cycle: D = T_ON / (T_ON + T_OFF) × 100%.'),
-- SET B
('22222222-2222-2222-2222-222222222222', 1, 'Define an Active Transducer with two examples.', 'A transducer that generates its own electrical output signal without requiring an external power source. Examples: piezoelectric sensor, thermocouple. It directly converts the input physical quantity into a voltage or current.'),
('22222222-2222-2222-2222-222222222222', 2, 'Define a Microcontroller.', 'A compact integrated circuit designed for embedded applications, containing a processor core, memory (RAM/ROM), and programmable I/O peripherals on a single chip.'),
('22222222-2222-2222-2222-222222222222', 3, 'Describe PID control and write the control equation.', 'A PID controller computes error e(t)=r(t)-y(t) and outputs u(t)=Kp·e(t) + Ki·∫e dt + Kd·de/dt. P: responds to present error. I: eliminates steady-state error. D: anticipates future error, improves stability. Laplace: U(s) = (Kp + Ki/s + Kd·s) E(s).'),
('22222222-2222-2222-2222-222222222222', 4, 'Describe a Proportional-Derivative (PD) controller.', 'Transfer function: Gc(s) = Kp + Kd·s. Adds a zero at s = -Kp/Kd. Advantages: improves transient response, reduces overshoot, increases damping. Disadvantage: does NOT eliminate steady-state error. Used in servo motors and position control.'),
('22222222-2222-2222-2222-222222222222', 5, 'List seven types of robot sensors and their applications.', '1) Vision (camera) – inspection, navigation. 2) Ultrasonic – obstacle avoidance, distance. 3) LIDAR – 3D mapping, autonomous navigation. 4) Force/torque – assembly, grinding. 5) Inductive proximity – end-of-travel, presence. 6) IMU – orientation, balance. 7) Tactile – slip detection, safe HRI.'),
('22222222-2222-2222-2222-222222222222', 6, 'Describe three types of industrial robots.', '1) Articulated – rotary joints, human-arm-like, used for welding, painting, assembly. 2) SCARA – two parallel rotary joints + vertical linear axis, used for pick-and-place, PCB assembly. 3) Cartesian (gantry) – three linear axes X,Y,Z, used in CNC, 3D printing, heavy transfer.'),
('22222222-2222-2222-2222-222222222222', 7, 'Write Boolean equations for: pass-through, NOT, AND, OR, XOR using inputs I:1 and I:2.', 'O:1 = I:1 (pass-through). O:2 = NOT I:1. O:3 = I:1 · I:2 (AND). O:4 = I:1 + I:2 (OR). O:5 = (I:1·¬I:2) + (I:2·¬I:1) (XOR – true when inputs differ).'),
('22222222-2222-2222-2222-222222222222', 8, 'Describe the architecture of a PLC.', '1) Power Supply – converts AC mains to DC for the backplane. 2) CPU – executes user program. 3) Memory – ROM (OS) and RAM (user logic & data). 4) Input modules – interface sensors/switches. 5) Output modules – drive actuators/relays. 6) Programming device (PC with RSLogix, TIA Portal). 7) Communication ports (Ethernet, RS-232, Profibus). 8) Timers/counters.'),
('22222222-2222-2222-2222-222222222222', 9, 'For G(s) = (1/2)·(s^2+4)(1+2.5s)/[(s^2+2)(1+0.5s)] find poles, zeros and G(2).', 'Zeros: s^2+4=0 ⇒ s=±j2; s+0.4=0 ⇒ s=-0.4. Poles: s^2+2=0 ⇒ s=±j√2 ≈ ±j1.414; s+2=0 ⇒ s=-2. Evaluate at s=2: G(2) = 0.5 · (8·6)/(6·2) = 0.5·4 = 2.'),
('22222222-2222-2222-2222-222222222222', 10, 'Solve x'''' + 2x'' + 2x = 0, x(0)=0, x''(0)=1 using Laplace.', 'Transform: s^2 X - 1 + 2sX + 2X = 0 ⇒ X(s) = 1/(s^2+2s+2). Complete the square: s^2+2s+2 = (s+1)^2 + 1. Match e^(-at) sin(bt) ↔ b/[(s+a)^2+b^2] with a=1, b=1. Therefore x(t) = e^(-t) sin(t).'),
('22222222-2222-2222-2222-222222222222', 11, 'Find inverse Laplace of F(s) = (s+6)/[s(s+1)(s+3)].', 'PFD: A/s + B/(s+1) + C/(s+3). Cover-up: A = 6/(1·3) = 2; B = (-1+6)/[(-1)(2)] = 5/(-2) = -5/2; C = (-3+6)/[(-3)(-2)] = 3/6 = 1/2. Therefore f(t) = 2 - (5/2)e^(-t) + (1/2)e^(-3t).'),
('22222222-2222-2222-2222-222222222222', 12, 'Standard form of a second-order closed-loop system.', 'T(s) = ωn^2 / (s^2 + 2ζωn·s + ωn^2). Peak time Tp = π/ωd where ωd = ωn√(1-ζ^2). Overshoot Mp = exp(-πζ/√(1-ζ^2))·100%. Settling time Ts = 4/(ζωn) for 2% criterion.'),
('22222222-2222-2222-2222-222222222222', 13, 'General root locus rules (k > 0).', '1) Locus starts at open-loop poles (k=0) and ends at zeros or infinity (k→∞). 2) Number of branches = number of poles. 3) Locus is symmetric about the real axis. 4) Real-axis segments lie to the left of an odd count of real poles+zeros. 5) Asymptote angles = (2q+1)·180°/(P−Z). 6) Centroid σ = (Σpoles − Σzeros)/(P−Z). 7) Imaginary-axis crossings found via Routh array.'),
('22222222-2222-2222-2222-222222222222', 14, 'Principle of operation of a hydraulic flow control valve.', 'Hydraulic fluid under pressure flows through a variable orifice whose opening is set by a spool or needle. The spool position is moved by a solenoid, manual handle, or pilot pressure. Adjusting the orifice area regulates the volumetric flow rate (Q = Cd·A·√(2ΔP/ρ)). Pressure-compensated designs maintain constant flow despite load changes. Typical uses: actuator speed control in presses, lifts, and CNC machines.'),
('22222222-2222-2222-2222-222222222222', 15, 'Phase margin & gain crossover frequency – method.', 'Gain crossover ωgc: solve |G(jω)| = 1. Phase margin PM = 180° + ∠G(jωgc). Gain margin: GM = 1/|G(jωpc)| at the phase-crossover frequency where ∠G = -180°. Positive PM and GM indicate stability.');
